arguments.command:
# Let's write a C# script to parse the binlog and extract detailed info
cat > /tmp/analyze_binlog.csx << 'EOF'
#r "nuget: MSBuild.StructuredLogger, 2.2.385"

using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;
using System.Collections.Generic;

var binlogPath = "/tmp/sv-7b01236df65e4ee3b1e08c30bc2869b9/build.binlog";
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== BUILD SUMMARY ===");
Console.WriteLine($"Build Succeeded: {build.Succeeded}");
Console.WriteLine();

// Get all errors
var errors = build.FindChildrenRecursive<Error>().ToList();
Console.WriteLine($"=== ERRORS ({errors.Count}) ===");
foreach (var error in errors)
{
    Console.WriteLine($"  [{error.Code}] {error.File}({error.LineNumber},{error.ColumnNumber}): {error.Text}");
    Console.WriteLine($"    Project: {error.GetNearestParent<Project>()?.Name ?? "unknown"}");
    Console.WriteLine();
}

// Get all warnings
var warnings = build.FindChildrenRecursive<Warning>().ToList();
Console.WriteLine($"=== WARNINGS ({warnings.Count}) ===");
foreach (var warning in warnings)
{
    Console.WriteLine($"  [{warning.Code}] {warning.Text}");
    Console.WriteLine($"    Project: {warning.GetNearestParent<Project>()?.Name ?? "unknown"}");
    Console.WriteLine();
}

// Show project structure
Console.WriteLine("=== PROJECT BUILD ORDER ===");
var projects = build.FindChildrenRecursive<Project>().ToList();
foreach (var proj in projects)
{
    Console.WriteLine($"  {proj.Name} - Succeeded: {proj.Succeeded}");
}

// Check for dependency failures
Console.WriteLine();
Console.WriteLine("=== DEPENDENCY ANALYSIS ===");
var failedProjects = projects.Where(p => !p.Succeeded).Select(p => p.Name).Distinct().ToList();
Console.WriteLine($"Failed projects: {string.Join(", ", failedProjects)}");

EOF
