cat > /tmp/analyze_binlog2.csx << 'EOF'
#r "nuget: MSBuild.StructuredLogger, 2.2.385"

using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;
using System.Collections.Generic;

var binlogPath = "/tmp/sv-7b01236df65e4ee3b1e08c30bc2869b9/build.binlog";
var build = BinaryLog.ReadBuild(binlogPath);

// Look for NuGet/restore messages related to Services project
Console.WriteLine("=== RESTORE-RELATED MESSAGES FOR Services ===");
var allMessages = build.FindChildrenRecursive<Message>().ToList();
foreach (var msg in allMessages.Where(m => m.Text != null && 
    (m.Text.Contains("Newtonsoft") || m.Text.Contains("Services.csproj") || m.Text.Contains("PackageReference"))))
{
    Console.WriteLine($"  {msg.Text.Substring(0, Math.Min(200, msg.Text.Length))}");
}

Console.WriteLine();
Console.WriteLine("=== ITEMS ADDED (looking for references) ===");
var addItems = build.FindChildrenRecursive<AddItem>().ToList();
foreach (var item in addItems.Where(i => i.Name == "PackageReference"))
{
    Console.WriteLine($"  AddItem: {item.Name}");
    foreach (var child in item.Children)
    {
        Console.WriteLine($"    {child}");
    }
}

Console.WriteLine();
Console.WriteLine("=== SOURCE FILE CONTENT IN BINLOG ===");
// Look for the actual source content embedded in the binlog  
var sourceFiles = build.FindChildrenRecursive<SourceFile>().ToList();
Console.WriteLine($"  Found {sourceFiles.Count} source files");
foreach (var sf in sourceFiles.Take(20))
{
    Console.WriteLine($"  File: {sf}");
}

// Look at the project evaluation to find references
Console.WriteLine();
Console.WriteLine("=== PROJECT EVALUATIONS ===");
var evaluations = build.FindChildrenRecursive<ProjectEvaluation>().ToList();
foreach (var eval in evaluations)
{
    Console.WriteLine($"  Evaluation: {eval.Name}");
    var items = eval.FindChildrenRecursive<AddItem>().Where(i => i.Name == "PackageReference").ToList();
    foreach (var item in items)
    {
        foreach (var child in item.Children)
        {
            Console.WriteLine($"    PackageRef: {child}");
        }
    }
}

EOF
