#r "nuget: MSBuild.StructuredLogger, 2.2.385"

using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;

var binlogPath = "/tmp/sv-7b01236df65e4ee3b1e08c30bc2869b9/build.binlog";
var build = BinaryLog.ReadBuild(binlogPath);

// Focus: find any PackageReference items in Services evaluation
var evaluations = build.FindChildrenRecursive<ProjectEvaluation>().ToList();
var servicesEval = evaluations.FirstOrDefault(e => e.Name == "Services.csproj");

Console.WriteLine("=== Services.csproj PackageReference items ===");
var items = servicesEval.FindChildrenRecursive<Item>().ToList();
var pkgRefs = items.Where(i => {
    var parent = i.Parent as AddItem ?? i.Parent as NamedNode;
    return parent != null && parent.Name == "PackageReference";
}).ToList();

if (!pkgRefs.Any())
{
    // Try broader search
    pkgRefs = items.Where(i => i.Text != null && i.Text.Contains("Newtonsoft")).ToList();
}

Console.WriteLine($"  Found {pkgRefs.Count} PackageReference items");
foreach (var pr in pkgRefs)
{
    Console.WriteLine($"    {pr.Text} (Parent: {pr.Parent?.GetType().Name} - {(pr.Parent as NamedNode)?.Name})");
}

// Look for the project file content in the binlog
Console.WriteLine("\n=== LOOKING FOR CSPROJ CONTENT ===");
var allNodes = build.FindChildrenRecursive<TreeNode>().ToList();
var projFileNodes = allNodes.Where(n => {
    var text = n.ToString();
    return text != null && text.Contains("Services.csproj") && text.Contains("Reading");
}).ToList();
Console.WriteLine($"  Found {projFileNodes.Count} project file read nodes");

// Get the actual references resolved for compilation
Console.WriteLine("\n=== RESOLVED REFERENCES FOR SERVICES ===");
var servicesBuilds = build.FindChildrenRecursive<Project>()
    .Where(p => p.Name == "Services.csproj")
    .ToList();

foreach (var proj in servicesBuilds)
{
    var targets = proj.FindChildrenRecursive<Target>().ToList();
    var resolveTarget = targets.FirstOrDefault(t => t.Name == "ResolvePackageAssets" || t.Name == "ResolveAssemblyReferences");
    if (resolveTarget != null)
    {
        Console.WriteLine($"  Target: {resolveTarget.Name}");
        var addItems = resolveTarget.FindChildrenRecursive<AddItem>().ToList();
        foreach (var ai in addItems.Where(a => a.Name == "Reference" || a.Name == "ReferencePath"))
        {
            foreach (var child in ai.Children.OfType<Item>().Where(c => c.Text.Contains("Json") || c.Text.Contains("Newtonsoft")))
            {
                Console.WriteLine($"    {child.Text}");
            }
        }
    }
}

// Check the assets file / lock file content
Console.WriteLine("\n=== NuGet RESTORE DETAILS ===");
var restoreMessages = build.FindChildrenRecursive<Message>()
    .Where(m => m.Text != null && m.Text.Contains("Newtonsoft"))
    .ToList();
foreach (var msg in restoreMessages)
{
    Console.WriteLine($"  {msg.Text.Substring(0, Math.Min(200, msg.Text.Length))}");
}

// Check if Api failed too
Console.WriteLine("\n=== API PROJECT ERRORS ===");
var apiProjects = build.FindChildrenRecursive<Project>()
    .Where(p => p.Name == "Api.csproj")
    .ToList();
foreach (var proj in apiProjects)
{
    var errors = proj.FindChildrenRecursive<Error>().ToList();
    if (errors.Any())
    {
        Console.WriteLine($"  Api.csproj had {errors.Count} errors:");
        foreach (var e in errors)
            Console.WriteLine($"    [{e.Code}] {e.Text}");
    }
}
Console.WriteLine("  (No errors in Api.csproj if nothing shown above)");

