    {
        var itemsList = new List<DictionaryEntry>();
        foreach (DictionaryEntry entry in ps.Items)
        {
            itemsList.Add(entry);
        }

        var pkgRefs = itemsList.Where(e => e.Key?.ToString() == "PackageReference").ToList();
        Console.WriteLine($"    PackageReference count: {pkgRefs.Count}");
        foreach (var pr in pkgRefs)
        {
            var taskItem = pr.Value as Microsoft.Build.Framework.ITaskItem;
            if (taskItem != null)
            {
                Console.WriteLine($"      Package: {taskItem.ItemSpec}");
                foreach (var meta in taskItem.MetadataNames.Cast<string>().Where(m => m == "Version"))
